import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GMPData {
  product_name: string;
  batch_number: string;
  change_content: string;
}

export interface ProcessingResult {
  data: GMPData[];
}

export interface FileState {
  file: File;
  base64: string;
  type: string;
  preview: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessingResult } from "../types";

const SYSTEM_INSTRUCTION = `Bạn là chuyên gia xử lý hồ sơ GMP ngành dược.
Nhiệm vụ:
1. Đọc toàn bộ nội dung từ file được cung cấp.
2. Không suy diễn, không bổ sung, không diễn giải lại câu chữ.
3. Trích xuất CHÍNH XÁC 3 thông tin sau:
   - Tên sản phẩm (product_name)
   - Số lô sản xuất (batch_number)
   - Nội dung sự thay đổi (change_content)
4. Gộp toàn bộ nội dung sự thay đổi thành MỘT dòng văn bản duy nhất.
5. Nếu có nhiều ý thay đổi, nối các ý bằng dấu “; ”.
6. Giữ nguyên cách diễn đạt gốc của tài liệu.
7. Nội dung thay đổi chỉ có 01 dòng, không xuống dòng.

CHỈ TRẢ VỀ JSON HỢP LỆ THEO CẤU TRÚC:
{
  "data": [
    {
      "product_name": "...",
      "batch_number": "...",
      "change_content": "..."
    }
  ]
}`;

export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: mimeType,
              },
            },
            {
              text: "Trích xuất dữ liệu từ tài liệu này theo đúng yêu cầu đã được cung cấp.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  product_name: { type: Type.STRING },
                  batch_number: { type: Type.STRING },
                  change_content: { type: Type.STRING },
                },
                required: ["product_name", "batch_number", "change_content"],
              },
            },
          },
          required: ["data"],
        },
      },
    });

    const text = response.text || "";
    return JSON.parse(text) as ProcessingResult;
  } catch (error) {
    console.error("Gemini processing error:", error);
    throw new Error("Không thể xử lý tài liệu. Vui lòng thử lại.");
  }
};

import React, { useState, useCallback } from 'react';
import { Upload, FileText, CheckCircle, AlertCircle, Loader2, Copy, Download, Trash2, ExternalLink } from 'lucide-react';
import { processGmpDocument } from './services/geminiService';
import { FileState, ProcessingResult } from './types';
import * as XLSX from 'xlsx';

const APP_SCRIPT_TEMPLATE = `function jsonToExcel(jsonInput) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("DATA");

  if (!sheet) sheet = ss.insertSheet("DATA");
  sheet.clear();

  const data = typeof jsonInput === 'string'
    ? JSON.parse(jsonInput)
    : jsonInput;

  const rows = data.data;
  if (!rows || rows.length === 0) return;

  const headers = Object.keys(rows[0]);
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  const values = rows.map(r => headers.map(h => r[h] ?? ""));
  sheet.getRange(2, 1, values.length, headers.length).setValues(values);
}`;

const App: React.FC = () => {
  const [fileState, setFileState] = useState<FileState | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileState({
        file,
        base64,
        type: file.type,
        preview: URL.createObjectURL(file)
      });
    };
    reader.readAsDataURL(file);
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await processGmpDocument(fileState.base64, fileState.type);
      setResult(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Đã xảy ra lỗi không xác định.");
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DATA");
    XLSX.writeFile(wb, `GMP_Extraction_${new Date().getTime()}.xlsx`);
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    setCopySuccess(label);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const reset = () => {
    setFileState(null);
    setResult(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <FileText className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-800">GMP Doc Processor</h1>
          </div>
          <div className="flex items-center gap-2 text-xs font-medium text-slate-500 uppercase tracking-wider">
            Expert Module • Pharmaceutical Industry
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto w-full px-4 py-8">
        <div className="grid lg:grid-cols-2 gap-8">

          {/* Left Panel: Upload & Preview */}
          <div className="space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border p-6">
              <h2 className="text-lg font-semibold text-slate-800 mb-4">Tải tài liệu lên</h2>
              {!fileState ? (
                <div className="border-2 border-dashed border-slate-200 rounded-xl p-10 flex flex-col items-center justify-center gap-4 hover:border-blue-400 hover:bg-blue-50/30 transition-all cursor-pointer relative">
                  <input 
                    type="file" 
                    onChange={handleFileChange} 
                    accept="image/*,application/pdf"
                    className="absolute inset-0 opacity-0 cursor-pointer"
                  />
                  <div className="bg-blue-100 p-4 rounded-full">
                    <Upload className="text-blue-600 w-8 h-8" />
                  </div>
                  <div className="text-center">
                    <p className="text-slate-700 font-medium">Click để chọn hoặc kéo thả file</p>
                    <p className="text-slate-400 text-sm mt-1">Hỗ trợ PDF, PNG, JPG (Max 10MB)</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="flex items-center justify-between bg-slate-100 p-3 rounded-lg border border-slate-200">
                    <div className="flex items-center gap-3 overflow-hidden">
                      <FileText className="text-blue-500 flex-shrink-0" />
                      <span className="text-sm font-medium text-slate-700 truncate">{fileState.file.name}</span>
                    </div>
                    <button onClick={reset} className="text-slate-400 hover:text-red-500 p-1 transition-colors">
                      <Trash2 size={18} />
                    </button>
                  </div>

                  {fileState.type.startsWith('image/') && (
                    <div className="relative rounded-xl overflow-hidden border bg-slate-50 aspect-video flex items-center justify-center">
                      <img src={fileState.preview} alt="Preview" className="max-h-full object-contain" />
                    </div>
                  )}

                  {fileState.type === 'application/pdf' && (
                    <div className="rounded-xl border bg-slate-50 p-8 flex flex-col items-center justify-center gap-3">
                      <FileText size={48} className="text-slate-300" />
                      <p className="text-slate-500 text-sm">Xem trước PDF chưa khả dụng trên giao diện nhanh</p>
                    </div>
                  )}

                  <button
                    disabled={loading}
                    onClick={handleProcess}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-semibold py-3 px-6 rounded-xl transition-all shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
                  >
                    {loading ? (
                      <>
                        <Loader2 className="animate-spin" />
                        Đang xử lý hồ sơ...
                      </>
                    ) : (
                      <>
                        <CheckCircle size={20} />
                        Bắt đầu trích xuất
                      </>
                    )}
                  </button>
                </div>
              )}
            </section>

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl flex items-start gap-3">
                <AlertCircle className="flex-shrink-0 mt-0.5" size={20} />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}
          </div>

          {/* Right Panel: Results */}
          <div className="space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border overflow-hidden min-h-[400px] flex flex-col">
              <div className="border-b px-6 py-4 bg-slate-50/50 flex items-center justify-between">
                <h2 className="text-lg font-semibold text-slate-800">Kết quả trích xuất</h2>
                {result && (
                  <div className="flex gap-2">
                    <button 
                      onClick={downloadExcel}
                      className="flex items-center gap-1.5 text-xs bg-green-600 hover:bg-green-700 text-white px-3 py-1.5 rounded-lg transition-colors"
                    >
                      <Download size={14} /> Xuất Excel
                    </button>
                  </div>
                )}
              </div>

              <div className="flex-1 p-6">
                {!result && !loading && (
                  <div className="h-full flex flex-col items-center justify-center text-slate-400 gap-4 opacity-60">
                    <div className="bg-slate-100 p-6 rounded-full">
                      <FileText size={40} strokeWidth={1.5} />
                    </div>
                    <p className="text-sm">Chưa có dữ liệu. Vui lòng tải file và trích xuất.</p>
                  </div>
                )}

                {loading && (
                  <div className="h-full flex flex-col items-center justify-center text-blue-500 gap-4">
                    <Loader2 className="animate-spin w-12 h-12" />
                    <div className="text-center">
                      <p className="font-semibold">Gemini AI đang phân tích...</p>
                      <p className="text-slate-400 text-sm mt-1">Đang đọc nội dung và cấu trúc lại JSON</p>
                    </div>
                  </div>
                )}

                {result && (
                  <div className="space-y-6">
                    {result.data.map((item, idx) => (
                      <div key={idx} className="bg-slate-50 rounded-xl p-4 border border-slate-200 space-y-3">
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block mb-1">Tên Sản Phẩm</label>
                            <p className="text-sm font-semibold text-slate-800">{item.product_name || 'N/A'}</p>
                          </div>
                          <div>
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block mb-1">Số Lô</label>
                            <p className="text-sm font-semibold text-slate-800">{item.batch_number || 'N/A'}</p>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider block mb-1">Nội dung thay đổi</label>
                          <p className="text-sm text-slate-600 leading-relaxed italic border-l-2 border-blue-400 pl-3 py-1">
                            {item.change_content || 'N/A'}
                          </p>
                        </div>
                      </div>
                    ))}

                    <div className="mt-8 pt-6 border-t space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-sm font-bold text-slate-700">App Script Output (Google Sheets)</h3>
                        <div className="flex gap-2">
                           <button 
                            onClick={() => copyToClipboard(JSON.stringify(result, null, 2), 'JSON')}
                            className="flex items-center gap-1.5 text-[11px] bg-slate-800 text-white px-2 py-1 rounded hover:bg-slate-700"
                          >
                            <Copy size={12} /> {copySuccess === 'JSON' ? 'Đã copy!' : 'Copy JSON'}
                          </button>
                        </div>
                      </div>

                      <div className="bg-slate-900 rounded-xl p-4 overflow-x-auto max-h-[300px] relative group">
                        <pre className="text-xs text-blue-300 font-mono">
                          {`// Script Function\n${APP_SCRIPT_TEMPLATE}\n\n// Current JSON Data\nconst jsonData = ${JSON.stringify(result, null, 2)};`}
                        </pre>
                        <button 
                          onClick={() => copyToClipboard(APP_SCRIPT_TEMPLATE, 'Script')}
                          className="absolute top-2 right-2 bg-white/10 hover:bg-white/20 p-2 rounded text-white backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Copy size={16} />
                        </button>
                      </div>

                      <div className="flex items-center gap-2 text-xs text-slate-400 bg-amber-50 p-3 rounded-lg border border-amber-100">
                        <ExternalLink size={14} className="text-amber-500 flex-shrink-0" />
                        <p>Bạn có thể copy script trên vào Google Apps Script để tự động hóa việc đưa dữ liệu vào bảng tính.</p>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </section>
          </div>
        </div>
      </main>

      <footer className="bg-white border-t py-6 text-center text-slate-400 text-sm">
        <p>&copy; 2024 GMP Document Processor Module. Powered by Gemini AI.</p>
      </footer>

      {/* Persistent Call-to-Action / Status for copy */}
      {copySuccess && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-800 text-white px-6 py-3 rounded-full shadow-2xl z-50 animate-bounce flex items-center gap-2">
          <CheckCircle size={18} className="text-green-400" />
          {copySuccess} đã được lưu vào Clipboard!
        </div>
      )}
    </div>
  );
};

export default App;

export type DocType = 'PHIEU_THAY_DOI' | 'BCSPKPH' | 'KHAC';

export interface GMPChangeData {
  product_name: string;
  batch_number: string;
  change_content: string;
}

export interface BCSPKPHData {
  nonconformity_code: string;
  product_name: string;
  batch_number: string;
  process_step: string;
  apply_date: string;
  nonconformity_content: string;
  root_cause: string;
  corrective_action: string;
}

export interface ProcessingResult {
  doc_type: DocType;
  data: (GMPChangeData | BCSPKPHData)[];
}

export interface FileState {
  file: File;
  base64: string;
  type: string;
  preview: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessingResult, DocType } from "../types";

const CLASSIFICATION_INSTRUCTION = `Dựa trên tiêu đề, nội dung và cấu trúc văn bản, hãy xác định loại biểu mẫu.
Chỉ trả về MỘT trong các giá trị sau (viết hoa, không giải thích):
- PHIEU_THAY_DOI
- BCSPKPH
- KHAC`;

const CHANGE_INSTRUCTION = `Bạn là chuyên gia xử lý hồ sơ GMP ngành dược.
Nhiệm vụ: Trích xuất CHÍNH XÁC: Tên sản phẩm (product_name), Số lô sản xuất (batch_number), Nội dung sự thay đổi (change_content).
Gộp toàn bộ nội dung sự thay đổi thành MỘT dòng văn bản duy nhất. Nối các ý bằng dấu “; ”. Giữ nguyên cách diễn đạt gốc.`;

const BCSPKPH_INSTRUCTION = `Bạn là chuyên gia xử lý hồ sơ QA/GMP ngành dược.
Nhiệm vụ: Phân tích nội dung văn bản của một biểu mẫu BCSPKPH. Không suy diễn, không bổ sung.
Trích xuất: 
- nonconformity_code (Mã số BC)
- product_name (Tên sản phẩm)
- batch_number (Số lô)
- process_step (Công đoạn)
- apply_date (Ngày áp dụng/phát hiện)
- nonconformity_content (Nội dung không phù hợp)
- root_cause (Nguyên nhân)
- corrective_action (Hành động khắc phục)`;

export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // 1. Classification
    const classResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: CLASSIFICATION_INSTRUCTION },
          ],
        },
      ],
    });

    const docType = (classResponse.text?.trim() || "KHAC") as DocType;

    // 2. Extraction based on type
    let systemInstruction = "";
    let schema: any = {};

    if (docType === "BCSPKPH") {
      systemInstruction = BCSPKPH_INSTRUCTION;
      schema = {
        type: Type.OBJECT,
        properties: {
          data: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                nonconformity_code: { type: Type.STRING },
                product_name: { type: Type.STRING },
                batch_number: { type: Type.STRING },
                process_step: { type: Type.STRING },
                apply_date: { type: Type.STRING },
                nonconformity_content: { type: Type.STRING },
                root_cause: { type: Type.STRING },
                corrective_action: { type: Type.STRING },
              },
            },
          },
        },
      };
    } else {
      // Default or PHIEU_THAY_DOI
      systemInstruction = CHANGE_INSTRUCTION;
      schema = {
        type: Type.OBJECT,
        properties: {
          data: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                product_name: { type: Type.STRING },
                batch_number: { type: Type.STRING },
                change_content: { type: Type.STRING },
              },
            },
          },
        },
      };
    }

    const extractionResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: "Trích xuất dữ liệu theo đúng cấu trúc JSON yêu cầu." },
          ],
        },
      ],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: schema,
      },
    });

    const parsedData = JSON.parse(extractionResponse.text || '{"data": []}');
    return {
      doc_type: docType,
      data: parsedData.data
    };
  } catch (error) {
    console.error("Gemini processing error:", error);
    throw new Error("Không thể xử lý tài liệu. Vui lòng thử lại.");
  }
};

import React, { useState } from 'react';
import { Upload, FileText, CheckCircle, AlertCircle, Loader2, Copy, Download, Trash2, ExternalLink, Tag } from 'lucide-react';
import { processGmpDocument } from './services/geminiService';
import { FileState, ProcessingResult } from './types';
import * as XLSX from 'xlsx';

const APP_SCRIPT_TEMPLATE = `function jsonToExcel(jsonInput) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("DATA");

  if (!sheet) sheet = ss.insertSheet("DATA");
  sheet.clear();

  const data = typeof jsonInput === 'string'
    ? JSON.parse(jsonInput)
