const APP_SCRIPT_TEMPLATE = `function jsonToExcel(jsonInput) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("DATA");

  if (!sheet) sheet = ss.insertSheet("DATA");
  sheet.clear();

  const data = typeof jsonInput === 'string'
    ? JSON.parse(jsonInput)
    : jsonInput;

  const rows = data.data;
  if (!rows || rows.length === 0) return;

  const headers = Object.keys(rows[0]);
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  const values = rows.map(r => headers.map(h => r[h] ?? ""));
  sheet.getRange(2, 1, values.length, headers.length).setValues(values);
}`;

const App: React.FC = () => {
  const [fileState, setFileState] = useState<FileState | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileState({
        file,
        base64,
        type: file.type,
        preview: URL.createObjectURL(file)
      });
    };
    reader.readAsDataURL(file);
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await processGmpDocument(fileState.base64, fileState.type);
      setResult(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Đã xảy ra lỗi không xác định.");
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DATA");
    XLSX.writeFile(wb, `GMP_${result.doc_type}_${new Date().getTime()}.xlsx`);
  };

  const copyToClipboard = (text: string, label: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopySuccess(label);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const reset = () => {
    setFileState(null);
    setResult(null);
    setError(null);
  };

  const getDocTypeLabel = (type: string) => {
    switch(type) {
      case 'BCSPKPH': return 'BC Sản Phẩm Không Phù Hợp';
