        title="Copy nội dung"
      >
        <Copy size={16} />
      </button>
    </div>
  );

  const CopyableTextArea = ({ label, value, italic = false }: { label: string, value: string, italic?: boolean }) => {
    const renderPart = (part: string) => {
      const trimmed = part.trim();
      if (trimmed.startsWith('ĐMVT:') || trimmed.startsWith('QTSX:')) {
        const [title, ...rest] = trimmed.split(':');
        return (
          <>
            <span className="font-bold text-blue-700">{title}:</span> {rest.join(':').trim()}
          </>
        );
      }
      return trimmed;
    };

    return (
      <div className="p-3 bg-white border rounded-lg group hover:border-blue-300 transition-colors relative">
        <div className="flex items-center justify-between mb-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase">{label}</label>
          <button 
            onClick={() => copyToClipboard(value, label)}
            className="p-1 text-slate-300 hover:text-blue-600 rounded transition-all opacity-0 group-hover:opacity-100"
          >
            <Copy size={14} />
          </button>
        </div>
        <div className={`text-sm text-slate-700 leading-relaxed ${italic ? 'italic' : ''}`}>
          {value ? value.split(';').map((part, i) => (
            <p key={i} className={i > 0 ? "mt-2 pt-2 border-t border-slate-100" : ""}>
              {renderPart(part)}
            </p>
          )) : '--'}
        </div>
      </div>
    );
  };

  return (
