- Trả về JSON theo đúng Schema được cung cấp.`;

export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: mimeType,
              },
            },
            {
              text: "Trích xuất dữ liệu. Chú ý định dạng 'change_content' với 1. ĐMVT và 2. QTSX, sử dụng dấu / ở đầu dòng, xuống dòng giữa nội dung hiện hành và thay đổi, và dùng ** để tô đậm sự thay đổi.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 4000 },
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            doc_type: { 
              type: Type.STRING, 
              enum: ["PHIEU_THAY_DOI", "BCSPKPH", "KHAC"],
              description: "Loại tài liệu được xác định"
            },
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  // BCSPKPH Fields
                  nonconformity_code: { type: Type.STRING },
                  process_step: { type: Type.STRING },
                  apply_date: { type: Type.STRING },
                  nonconformity_content: { type: Type.STRING },
                  root_cause: { type: Type.STRING },
                  corrective_action: { type: Type.STRING },
                  // Shared Fields
                  product_name: { type: Type.STRING },
                  batch_number: { type: Type.STRING },
                  // Change Fields
                  change_content: { type: Type.STRING },
                },
              },
            },
          },
          required: ["doc_type", "data"],
        },
      },
    });

    const text = response.text || "";
    return JSON.parse(text) as ProcessingResult;
  } catch (error) {
    console.error("Gemini processing error:", error);
    throw new Error("Không thể trích xuất nội dung. Vui lòng kiểm tra lại chất lượng ảnh/file và thử lại.");
  }
};

