import React, { useState } from 'react';
import { Upload, FileText, CheckCircle, AlertCircle, Loader2, Copy, Download, Trash2, Tag } from 'lucide-react';
import { processGmpDocument } from './services/geminiService';
import { FileState, ProcessingResult } from './types';
import * as XLSX from 'xlsx';

const APP_SCRIPT_TEMPLATE = `function jsonToExcel(jsonInput) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName("DATA");

  if (!sheet) sheet = ss.insertSheet("DATA");
  sheet.clear();

  const data = typeof jsonInput === 'string'
    ? JSON.parse(jsonInput)
    : jsonInput;

  const rows = data.data;
  if (!rows || rows.length === 0) return;

  const headers = Object.keys(rows[0]);
  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);

  const values = rows.map(r => headers.map(h => r[h] ?? ""));
  sheet.getRange(2, 1, values.length, headers.length).setValues(values);
}`;

const App: React.FC = () => {
  const [fileState, setFileState] = useState<FileState | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFileState({
        file,
        base64,
        type: file.type,
        preview: URL.createObjectURL(file)
      });
    };
    reader.readAsDataURL(file);
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const data = await processGmpDocument(fileState.base64, fileState.type);
      setResult(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Đã xảy ra lỗi không xác định.");
    } finally {
      setLoading(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DATA");
    XLSX.writeFile(wb, `GMP_${result.doc_type}_${new Date().getTime()}.xlsx`);
  };

  const copyToClipboard = (text: string, label: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopySuccess(label);
    setTimeout(() => setCopySuccess(null), 2000);
  };

  const reset = () => {
    setFileState(null);
    setResult(null);
    setError(null);
  };

  const getDocTypeLabel = (type: string) => {
    switch(type) {
      case 'BCSPKPH': return 'BC Sản Phẩm Không Phù Hợp';
      case 'PHIEU_THAY_DOI': return 'Phiếu Thay Đổi';
      default: return 'Tài liệu khác';
    }
  };

  const CopyableRow = ({ label, value }: { label: string, value: string }) => (
    <div className="flex items-center justify-between gap-4 p-3 bg-white border rounded-lg group hover:border-blue-300 transition-colors">
      <div className="flex-1 min-w-0">
        <label className="text-[10px] font-bold text-slate-400 uppercase block mb-0.5">{label}</label>
        <p className="text-sm font-semibold text-slate-800 truncate">{value || '--'}</p>
      </div>
      <button 
        onClick={() => copyToClipboard(value, label)}
        className="flex-shrink-0 p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-md transition-all opacity-0 group-hover:opacity-100"
        title="Copy nội dung"
      >
        <Copy size={16} />
      </button>
    </div>
  );

  const CopyableTextArea = ({ label, value, italic = false }: { label: string, value: string, italic?: boolean }) => {
    const renderContent = (text: string) => {
      // Handle bold formatting **text**
      const parts = text.split(/(\*\*.*?\*\*)/g);
      return parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="text-blue-800 font-extrabold px-1 bg-blue-50 rounded">{part.slice(2, -2)}</strong>;
        }
        return part;
      });
    };

    const renderLines = (text: string) => {
      if (!text) return '--';
      return text.split('\n').map((line, i) => {
        const trimmed = line.trim();
        // Highlight "1." or "2." sections
        if (trimmed.match(/^[12]\./)) {
          return (
            <div key={i} className="mt-4 first:mt-0 font-bold text-blue-900 border-b-2 border-blue-100 pb-1 mb-2">
              {renderContent(trimmed)}
            </div>
          );
        }
        // Highlight bullet points "- "
        if (trimmed.startsWith('-')) {
          return (
            <div key={i} className="pl-6 py-1 border-l-4 border-slate-100 ml-1 text-slate-700 relative">
              <span className="absolute left-0 top-1 text-slate-300 font-bold">•</span>
              {renderContent(trimmed)}
            </div>
          );
        }
        return (
          <div key={i} className="py-0.5 text-slate-600 pl-2">
            {renderContent(line)}
          </div>
        );
      });
    };

    return (
      <div className="p-4 bg-white border rounded-xl group hover:border-blue-300 transition-colors relative shadow-sm">
        <div className="flex items-center justify-between mb-3">
          <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest">{label}</label>
          <button 
            onClick={() => copyToClipboard(value, label)}
            className="p-1.5 text-slate-300 hover:text-blue-600 rounded-lg transition-all opacity-0 group-hover:opacity-100 bg-slate-50"
          >
            <Copy size={14} />
          </button>
        </div>
        <div className={`text-sm leading-relaxed whitespace-pre-wrap ${italic ? 'italic' : ''}`}>
          {renderLines(value)}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-md shadow-blue-200">
              <FileText className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-800">Trích xuất tài liệu</h1>
          </div>
          <div className="hidden sm:flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
            Phòng Đảm Bảo Chất Lượng (QA)
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-6xl mx-auto w-full px-4 py-8">
        <div className="grid lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border p-6">
              <h2 className="text-lg font-semibold text-slate-800 mb-4">Tải tài liệu lên</h2>
              {!fileState ? (
                <div className="border-2 border-dashed border-slate-200 rounded-xl p-10 flex flex-col items-center justify-center gap-4 hover:border-blue-400 hover:bg-blue-50/30 transition-all cursor-pointer relative">
                  <input 
                    type="file" 
                    onChange={handleFileChange} 
                    accept="image/*,application/pdf"
                    className="absolute inset-0 opacity-0 cursor-pointer"
                  />
                  <div className="bg-blue-100 p-4 rounded-full">
                    <Upload className="text-blue-600 w-8 h-8" />
                  </div>
                  <div className="text-center">
                    <p className="text-slate-700 font-medium">Click để chọn tài liệu</p>
                    <p className="text-slate-400 text-sm mt-1">Hỗ trợ PDF, Ảnh (STĐ, BCSPKPH...)</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="flex items-center justify-between bg-slate-100 p-3 rounded-lg border border-slate-200">
                    <div className="flex items-center gap-3 overflow-hidden">
                      <FileText className="text-blue-500 flex-shrink-0" />
                      <span className="text-sm font-medium text-slate-700 truncate">{fileState.file.name}</span>
                    </div>
                    <button onClick={reset} className="text-slate-400 hover:text-red-500 p-1 transition-colors">
                      <Trash2 size={18} />
                    </button>
                  </div>
                  {fileState.type.startsWith('image/') && (
                    <div className="relative rounded-xl overflow-hidden border bg-slate-50 aspect-video flex items-center justify-center">
                      <img src={fileState.preview} alt="Preview" className="max-h-full object-contain" />
                    </div>
                  )}
                  <button
                    disabled={loading}
                    onClick={handleProcess}
                    className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-semibold py-3 px-6 rounded-xl transition-all shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
                  >
                    {loading ? (
                      <><Loader2 className="animate-spin" /> Đang phân tích & trích xuất...</>
                    ) : (
                      <><CheckCircle size={20} /> Bắt đầu xử lý</>
                    )}
                  </button>
                </div>
              )}
            </section>
            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl flex items-start gap-3">
                <AlertCircle className="flex-shrink-0 mt-0.5" size={20} />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}
          </div>

          <div className="space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border overflow-hidden min-h-[400px] flex flex-col">
              <div className="border-b px-6 py-4 bg-slate-50/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <h2 className="text-lg font-semibold text-slate-800">Kết quả trích xuất</h2>
                  {result && (
                    <span className="px-2 py-0.5 bg-blue-100 text-blue-700 text-[10px] font-bold rounded uppercase tracking-tighter flex items-center gap-1">
                      <Tag size={10} /> {result.doc_type}
                    </span>
                  )}
                </div>
                {result && (
                  <button 
                    onClick={downloadExcel}
                    className="flex items-center gap-1.5 text-xs bg-green-600 hover:bg-green-700 text-white px-3 py-1.5 rounded-lg shadow-sm transition-all active:scale-95"
                  >
                    <Download size={14} /> Xuất Excel
                  </button>
                )}
              </div>

              <div className="flex-1 p-6">
                {!result && !loading && (
                  <div className="h-full flex flex-col items-center justify-center text-slate-400 gap-4 opacity-60">
                    <div className="bg-slate-100 p-6 rounded-full">
                      <FileText size={40} strokeWidth={1.5} />
                    </div>
                    <p className="text-sm">Chưa có kết quả trích xuất.</p>
                  </div>
                )}
                {loading && (
                  <div className="h-full flex flex-col items-center justify-center text-blue-500 gap-4">
                    <Loader2 className="animate-spin w-12 h-12" />
                    <div className="text-center">
                      <p className="font-semibold text-slate-700">AI đang xử lý dữ liệu...</p>
                      <p className="text-slate-400 text-sm mt-1">Đang đọc chi tiết hồ sơ GMP</p>
                    </div>
                  </div>
                )}
                {result && (
                  <div className="space-y-6">
                    <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 flex items-center gap-2">
                      <CheckCircle className="text-blue-500" size={16} />
                      <span className="text-xs font-bold text-blue-800 uppercase tracking-tight">
                        {getDocTypeLabel(result.doc_type)}
                      </span>
                    </div>
                    {result.data.map((item: any, idx) => (
                      <div key={idx} className="bg-slate-50 rounded-xl p-4 border border-slate-200 space-y-3">
                        {result.doc_type === 'BCSPKPH' ? (
                          <div className="space-y-3">
                            <CopyableRow label="Mã Số BC" value={item.nonconformity_code} />
                            <CopyableRow label="Ngày Áp Dụng" value={item.apply_date} />
                            <CopyableRow label="Tên Sản Phẩm" value={item.product_name} />
                            <CopyableRow label="Số Lô" value={item.batch_number} />
                            <CopyableRow label="Công Đoạn" value={item.process_step} />
                            <div className="grid grid-cols-1 gap-3 pt-2">
                              <CopyableTextArea label="Nội Dung Không Phù Hợp" value={item.nonconformity_content} />
                              <CopyableTextArea label="Nguyên Nhân Gốc" value={item.root_cause} />
                              <CopyableTextArea label="Hành Động Khắc Phục" value={item.corrective_action} italic />
                            </div>
                          </div>
                        ) : (
                          <div className="space-y-3">
                            <CopyableRow label="Tên Sản Phẩm" value={item.product_name} />
                            <CopyableRow label="Số Lô" value={item.batch_number} />
                            <CopyableTextArea label="Nội dung thay đổi chi tiết" value={item.change_content} />
                          </div>
                        )}
                      </div>
                    ))}
                    <div className="mt-8 pt-6 border-t space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-sm font-bold text-slate-700">Tích hợp Apps Script</h3>
                        <div className="flex gap-2">
                           <button 
                            onClick={() => copyToClipboard(JSON.stringify(result, null, 2), 'Dữ liệu JSON')}
                            className="flex items-center gap-1.5 text-[10px] font-bold bg-slate-800 text-white px-3 py-1.5 rounded hover:bg-slate-700 transition-colors"
                          >
                            <Copy size={12} /> JSON
                          </button>
                        </div>
                      </div>
                      <div className="bg-slate-900 rounded-xl p-4 overflow-x-auto max-h-[300px] relative group border border-slate-800">
                        <pre className="text-[10px] text-blue-300 font-mono leading-relaxed">
                          {`// Google Apps Script Utility\n${APP_SCRIPT_TEMPLATE}\n\n// Current Data Payload\nconst input = ${JSON.stringify(result, null, 2)};`}
                        </pre>
                        <button 
                          onClick={() => copyToClipboard(APP_SCRIPT_TEMPLATE, 'Mã Script')}
                          className="absolute top-3 right-3 bg-white/10 hover:bg-white/20 p-2 rounded text-white backdrop-blur-md opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Copy size={16} />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            </section>
          </div>
        </div>
      </main>

      <footer className="bg-white border-t py-6 text-center text-slate-400 text-[10px] font-medium uppercase tracking-widest">
        <p>&copy; 2024 QA/GMP Smart Document Extraction System</p>
      </footer>

      {copySuccess && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-2xl shadow-2xl z-50 flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300 border border-slate-700">
          <div className="bg-green-500 rounded-full p-1 shadow-sm shadow-green-200">
            <CheckCircle size={14} className="text-white" />
          </div>
          <span className="text-sm font-medium">Đã copy {copySuccess}!</span>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessingResult, DocType } from "../types";

const SYSTEM_INSTRUCTION = `Bạn là chuyên gia QA/GMP ngành dược hàng đầu, có kinh nghiệm dày dặn trong việc soát xét hồ sơ lô và phiếu thay đổi.
Nhiệm vụ của bạn là trích xuất dữ liệu từ hình ảnh hoặc PDF với độ chính xác tuyệt đối.

QUY TẮC CỐ ĐỊNH:
1. Phân loại tài liệu (doc_type):
   - 'PHIEU_THAY_DOI': Phiếu đề nghị thay đổi, phiếu thông báo sửa đổi, hoặc các văn bản tương đương.
   - 'BCSPKPH': Báo cáo sản phẩm không phù hợp, biên bản xử lý SPKPH.
   - 'KHAC': Tài liệu khác.

2. Trích xuất dữ liệu (Không suy diễn, giữ nguyên văn phong gốc):

DÀNH CHO 'BCSPKPH':
- nonconformity_code: Lấy mã số báo cáo. LOẠI BỎ phần đuôi "/BC SPKPH" nếu có.
- product_name: Tên sản phẩm đầy đủ.
- batch_number: Số lô sản xuất.
- process_step: Công đoạn xảy ra sự cố.
- apply_date: Định dạng DD/MM/YY.
- nonconformity_content, root_cause, corrective_action: Gộp thành 01 dòng duy nhất cho mỗi trường.

DÀNH CHO 'PHIEU_THAY_DOI':
- product_name: Tên sản phẩm.
- batch_number: Số lô sản xuất.
- change_content: TRÌNH BÀY CHÍNH XÁC THEO CẤU TRÚC SAU (sử dụng \\n để xuống dòng):
    1. ĐMVT: [Nội dung ghi chú vật tư...]
    2. QTSX:
    - Nội dung hiện hành: [Mô tả chi tiết nội dung cũ]
    - Nội dung thay đổi: [Mô tả chi tiết nội dung mới. BẮT BUỘC dùng **...** để bao bọc các từ ngữ/thông số thực sự được thay đổi so với nội dung cũ]

LƯU Ý QUAN TRỌNG:
- Nếu tài liệu không có phần ĐMVT hoặc QTSX, hãy ghi "Không có thay đổi".
- Nếu có nhiều thay đổi trong QTSX, hãy liệt kê từng cặp "- Nội dung hiện hành" và "- Nội dung thay đổi" xuống dòng nhau.
- Tuyệt đối không tự ý thêm các từ như "AI trích xuất", "Theo tài liệu...".
- Đảm bảo JSON trả về là hợp lệ và các trường không chứa ký tự xuống dòng thực tế (chỉ dùng ký tự thoát \\n).`;

export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Sử dụng model Pro để có độ chính xác cao nhất cho hồ sơ GMP phức tạp
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: mimeType,
              },
            },
            {
              text: "Hãy đọc kỹ tài liệu này. Trích xuất chính xác Tên sản phẩm, Số lô và chi tiết thay đổi. Đối với Phiếu thay đổi, hãy tách rõ 1. ĐMVT và 2. QTSX theo đúng định dạng yêu cầu, tô đậm phần thay đổi.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 8000 }, // Tăng thinking budget để model suy luận kỹ hơn về các bảng dữ liệu
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            doc_type: { 
              type: Type.STRING, 
              enum: ["PHIEU_THAY_DOI", "BCSPKPH", "KHAC"],
              description: "Loại tài liệu được xác định"
            },
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  nonconformity_code: { type: Type.STRING },
                  process_step: { type: Type.STRING },
                  apply_date: { type: Type.STRING },
                  nonconformity_content: { type: Type.STRING },
                  root_cause: { type: Type.STRING },
                  corrective_action: { type: Type.STRING },
                  product_name: { type: Type.STRING },
                  batch_number: { type: Type.STRING },
                  change_content: { type: Type.STRING },
                },
              },
            },
          },
          required: ["doc_type", "data"],
        },
      },
    });

    const text = response.text || "";
    return JSON.parse(text) as ProcessingResult;
  } catch (error) {
    console.error("Gemini processing error:", error);
    throw new Error("Lỗi khi trích xuất dữ liệu. Vui lòng thử lại với hình ảnh rõ nét hơn hoặc kiểm tra kết nối mạng.");
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessingResult, DocType } from "../types";

const SYSTEM_INSTRUCTION = `Bạn là chuyên gia QA/GMP ngành dược hàng đầu.
Nhiệm vụ của bạn là:
1. Phân tích tài liệu hình ảnh/PDF để xác định loại biểu mẫu:
   - 'PHIEU_THAY_DOI': Phiếu đề nghị thay đổi/sửa đổi hoặc Phiếu thông báo thay đổi.
   - 'BCSPKPH': Báo cáo sản phẩm không phù hợp.
   - 'KHAC': Các loại tài liệu khác.

2. Trích xuất dữ liệu CHÍNH XÁC theo các quy tắc sau:

DÀNH CHO 'BCSPKPH':
- nonconformity_code (Mã số BC): Bắt buộc LOẠI BỎ cụm từ "BC SPKPH" ở cuối mã (Ví dụ: "123/BC SPKPH" -> "123").
- product_name (Tên sản phẩm): Giữ nguyên văn bản gốc.
- batch_number (Số lô): Giữ nguyên văn bản gốc.
- process_step (Công đoạn): Giữ nguyên văn bản gốc.
- apply_date (Ngày áp dụng): Định dạng DD/MM/YY (Năm chỉ lấy 02 số cuối).
- nonconformity_content (Nội dung không phù hợp): Gộp thành 01 dòng duy nhất.
- root_cause (Nguyên nhân): Gộp thành 01 dòng duy nhất.
- corrective_action (Hành động khắc phục): Gộp thành 01 dòng duy nhất.

DÀNH CHO 'PHIEU_THAY_DOI':
- product_name (Tên sản phẩm)
- batch_number (Số lô)
- change_content (Nội dung thay đổi): Trình bày theo cấu trúc đánh số thứ tự như sau:
    1. ĐMVT: [Nội dung ghi chú vật tư...]
    2. QTSX: 
       - Nội dung hiện hành: [Mô tả nội dung cũ...]
       - Nội dung thay đổi: [Mô tả nội dung mới, BẮT BUỘC sử dụng dấu **...** để bao bọc những phần thực sự thay đổi so với nội dung cũ]
    (Nếu có nhiều thay đổi trong QTSX, lặp lại dấu gạch ngang "-" cho mỗi mục. Sử dụng ký tự xuống dòng \\n để phân tách các dòng trong cùng một chuỗi JSON).

QUY TẮC CHUNG:
- Không suy diễn, không thêm bớt từ ngữ.
- Giữ nguyên cách diễn đạt gốc của tài liệu.
- Đối với 'PHIEU_THAY_DOI', sử dụng ký tự \\n bên trong chuỗi để tạo dòng mới như yêu cầu.
- Các phần thay đổi quan trọng phải được bao bọc bởi ** để hiển thị đậm.
- Trả về JSON theo đúng Schema được cung cấp.`;

export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: mimeType,
              },
            },
            {
              text: "Trích xuất dữ liệu. Chú ý định dạng 'change_content' với 1. ĐMVT và 2. QTSX, sử dụng dấu '-' ở đầu dòng trong QTSX, xuống dòng giữa nội dung hiện hành và thay đổi, và dùng ** để tô đậm sự thay đổi.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 4000 },
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            doc_type: { 
              type: Type.STRING, 
              enum: ["PHIEU_THAY_DOI", "BCSPKPH", "KHAC"],
              description: "Loại tài liệu được xác định"
            },
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  // BCSPKPH Fields
                  nonconformity_code: { type: Type.STRING },
                  process_step: { type: Type.STRING },
                  apply_date: { type: Type.STRING },
                  nonconformity_content: { type: Type.STRING },
                  root_cause: { type: Type.STRING },
                  corrective_action: { type: Type.STRING },
                  // Shared Fields
                  product_name: { type: Type.STRING },
                  batch_number: { type: Type.STRING },
                  // Change Fields
                  change_content: { type: Type.STRING },
                },
              },
            },
          },
          required: ["doc_type", "data"],
        },
      },
    });

    const text = response.text || "";
    return JSON.parse(text) as ProcessingResult;
  } catch (error) {
    console.error("Gemini processing error:", error);
    throw new Error("Không thể trích xuất nội dung. Vui lòng kiểm tra lại chất lượng ảnh/file và thử lại.");
  }
};

