export const processGmpDocument = async (base64Data: string, mimeType: string): Promise<ProcessingResult> => {
  // Khởi tạo instance mới mỗi lần gọi để đảm bảo sử dụng API Key mới nhất
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Sử dụng Pro để xử lý logic trích xuất phức tạp tốt hơn
      contents: [
        {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: mimeType,
              },
            },
            {
